// ============================================================
// Recevoir job_id — Extraction défensive (pas de throw)
// ============================================================
const input = $input.first().json;
const job_id = input.job_id || input.payload?.job_id;
const correlation_id = input.correlation_id || input.payload?.correlation_id || '';
const incoming_message_id = input.message_id || input.payload?.message_id || null;

if (!job_id) {
  return [{ json: {
    _init_valid: false,
    _error_code: 'MISSING_JOB_ID',
    _error_message: 'Champ obligatoire manquant: job_id',
    correlation_id,
    incoming_message_id
  } }];
}

return [{ json: {
  _init_valid: true,
  tenant_id: input.tenant_id || 1,
  job_id,
  correlation_id,
  incoming_message_id
} }];

// Réponse immédiate si job_id manquant — pas de log (aucun job à référencer)
const d = $input.first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  status: 'ERROR',
  source: 'PUBLICATION_AGENT',
  target: 'ORCHESTRATOR',
  correlation_id: d.correlation_id || '',
  in_reply_to: d.incoming_message_id || null,
  payload: {
    job_id: null,
    result_status: 'FAILED_SYSTEM',
    error_code: d._error_code,
    error_message: d._error_message
  }
} }];

const d = $('Recevoir job_id').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  agent: 'PUBLICATION_AGENT',
  event_type: 'PUBLICATION_STARTED',
  message: `Publication démarrée pour ${d.job_id}`,
  job_id: d.job_id,
  correlation_id: d.correlation_id
} }];

// ============================================================
// Extraire Job + Valider statut ADAPTED + retry_count
// Correction : validation complète AVANT appel CredentialsService
// ============================================================
const jobResult = $input.first().json;
const initData  = $('Recevoir job_id').first().json;

// --- Job existe ? ---
if (!jobResult.success || !jobResult.job) {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...initData, _job_valid: false,
    _result_status: 'FAILED_PRE_PUBLICATION',
    _error_code: 'JOB_NOT_FOUND',
    _error_message: `Job ${initData.job_id} introuvable`
  } }];
}

const job = jobResult.job;
let payload = job.payload;
if (typeof payload === 'string') {
  try { payload = JSON.parse(payload); } catch(e) {
    return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
      ...initData, job, _job_valid: false,
      _result_status: 'FAILED_PRE_PUBLICATION',
      _error_code: 'INVALID_PAYLOAD',
      _error_message: `Payload JSON invalide pour ${job.job_id}`
    } }];
  }
}

// --- Statut ADAPTED ? (UC-03 §7.1) ---
if (job.status !== 'ADAPTED') {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...initData, job, payload, _job_valid: false,
    _result_status: 'FAILED_PRE_PUBLICATION',
    _error_code: 'INVALID_JOB_STATUS',
    _error_message: `Statut attendu ADAPTED, reçu ${job.status}`
  } }];
}

// --- retry_count < retry_max ? (UC-03 §7.1) ---
const retryMax = job.retry_max || 3;
if ((job.retry_count || 0) >= retryMax) {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...initData, job, payload, _job_valid: false,
    _result_status: 'FAILED_PUBLICATION',
    _error_code: 'MAX_RETRIES_EXCEEDED',
    _error_message: `retry_count ${job.retry_count} >= retry_max ${retryMax}`
  } }];
}

// --- TOUT OK — Préparer appel CredentialsService ---
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  ...initData, job, payload, _job_valid: true,
  channel_name:   job.channel_name,
  diffusion_type: job.diffusion_type,
  credential_ref: job.credential_ref,
  action: 'GET_CREDENTIAL'
} }];

// ============================================================
// Validation complète pré-publication — UC-03 §7.2 + §7.3 + §7.4
// ============================================================
const credResult = $input.first().json;
const prev = $('Extraire + Valider Job').first().json;
const job = prev.job;
const payload = prev.payload;
const ch = prev.channel_name;
const dt = prev.diffusion_type;

function fail(code, msg, status) {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...prev, _pre_pub_valid: false,
    _result_status: status || 'FAILED_PRE_PUBLICATION',
    _error_code: code, _error_message: msg
  } }];
}

// ═══ §7.2 — Validation credentials ═══
if (!credResult.success || !credResult.credential) {
  return fail('CREDENTIAL_NOT_FOUND',
    `credential_ref ${prev.credential_ref} introuvable`, 'FAILED_CREDENTIALS');
}
const cred = credResult.credential;
const access_token = cred.access_token;

if (!access_token) {
  return fail('EMPTY_ACCESS_TOKEN', 'access_token vide ou null', 'FAILED_CREDENTIALS');
}

// Cohérence plateforme (UC-03 §7.2)
const credPlatform = (cred.platform || '').toUpperCase();
// Facebook et Instagram partagent Meta — accepter les deux
const metaPlatforms = ['FACEBOOK', 'INSTAGRAM'];
const platformMatch = metaPlatforms.includes(ch)
  ? metaPlatforms.includes(credPlatform) || credPlatform === 'META'
  : credPlatform === ch;
if (credPlatform && !platformMatch) {
  return fail('CREDENTIAL_PLATFORM_MISMATCH',
    `credential.platform=${cred.platform}, attendu ${ch}`, 'FAILED_CREDENTIALS');
}

// ═══ §7.4 — Planification ═══
if (job.scheduled_at) {
  const scheduledAt = new Date(job.scheduled_at);
  if (scheduledAt > new Date()) {
    return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
      ...prev, _pre_pub_valid: false,
      _result_status: 'PUBLICATION_DEFERRED',
      _error_code: 'SCHEDULED_FUTURE',
      _error_message: `scheduled_at ${job.scheduled_at} dans le futur`
    } }];
  }
}

// ═══ §7.3 — Validation structurelle du payload ═══
const content = payload.content;
if (!content || typeof content !== 'object') {
  return fail('MISSING_CONTENT', 'content absent ou null');
}
if (!content.text || typeof content.text !== 'string' || content.text.trim() === '') {
  return fail('MISSING_TEXT', 'content.text vide ou absent');
}
const pp = payload.platform_params;
if (!pp || typeof pp !== 'object') {
  return fail('MISSING_PLATFORM_PARAMS', 'platform_params absent ou null');
}

// ═══ §7.3 — Validations par canal ═══
if (ch === 'FACEBOOK') {
  if (!pp.page_id) return fail('MISSING_PAGE_ID', 'page_id absent dans platform_params');
}
if (ch === 'INSTAGRAM') {
  if (!pp.account_id && !pp.ig_account_id) {
    return fail('MISSING_ACCOUNT_ID', 'account_id absent pour Instagram');
  }
  if (!content.media || !Array.isArray(content.media) || content.media.length === 0) {
    return fail('MISSING_MEDIA', 'media obligatoire pour Instagram');
  }
}
if (ch === 'LINKEDIN') {
  if (!pp.author_urn) return fail('MISSING_AUTHOR_URN', 'author_urn absent pour LinkedIn');
  if (!pp.visibility)  return fail('MISSING_VISIBILITY', 'visibility absent pour LinkedIn');
}

// ═══ §7.3 — Validations PAID ═══
if (dt === 'PAID') {
  if (!payload.ads || typeof payload.ads !== 'object') {
    return fail('MISSING_ADS_BLOCK', 'Bloc ads absent pour PAID');
  }
  if ((ch === 'FACEBOOK' || ch === 'INSTAGRAM') && !pp.cta_type) {
    return fail('MISSING_CTA', 'cta_type absent pour PAID');
  }
  if (ch === 'FACEBOOK') {
    if (!pp.ad_format) return fail('MISSING_AD_FORMAT', 'ad_format absent pour PAID Facebook');
    if (!payload.ads.campaign_params?.objective) {
      return fail('MISSING_CAMPAIGN_OBJECTIVE', 'campaign_params.objective absent');
    }
    if (!payload.ads.adset_params?.targeting) {
      return fail('MISSING_TARGETING', 'adset_params.targeting absent');
    }
    if (!payload.ads.adset_params?.placements) {
      return fail('MISSING_PLACEMENTS', 'adset_params.placements absent');
    }
  }
  if (ch === 'INSTAGRAM' && !content.link?.url) {
    return fail('MISSING_LINK_URL', 'content.link.url absent pour Instagram PAID');
  }
  if (ch === 'LINKEDIN') {
    if (!payload.ads.campaign_params?.objective) {
      return fail('MISSING_CAMPAIGN_OBJECTIVE', 'campaign_params.objective absent pour LinkedIn PAID');
    }
    if (!content.link?.url) {
      return fail('MISSING_LINK_URL', 'content.link.url absent pour LinkedIn PAID');
    }
  }
  // Budget
  const budget = job.budget_amount || payload.ads?.budget_amount;
  const currency = job.budget_currency || payload.ads?.budget_currency;
  if (!budget || budget <= 0) return fail('INVALID_BUDGET', 'budget_amount invalide ou absent');
  if (!currency) return fail('INVALID_BUDGET', 'budget_currency absent');
}

// ═══ TOUT OK ═══
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  ...prev,
  _pre_pub_valid: true,
  access_token   // Seul le token transite — pas l'objet credential entier
} }];

const d = $('Valider Credentials + Pré-pub').first().json;
return [{ json: {
  action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id,
  job_id: d.job_id,
  fields: { status: 'PUBLISHING' }
} }];

// ============================================================
// ROUTAGE — Préparer payload standardisé (Adapter Pattern)
// ============================================================
const d = $('Valider Credentials + Pré-pub').first().json;
const ch = d.channel_name;

return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  job:            d.job,
  payload:        d.payload,
  access_token:   d.access_token,
  channel_name:   ch,
  diffusion_type: d.diffusion_type,
  job_id:         d.job_id,
  correlation_id: d.correlation_id,
  _channel:       ch
} }];

// ============================================================
// Fallback — Canal non supporté → format erreur connecteur
// Produit le même contrat que les connecteurs pour convergence
// ============================================================
const d = $input.first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  _success: false,
  _status: 'FAILED_PUBLICATION',
  _error_code: 'UNSUPPORTED_CHANNEL',
  _error_message: `Canal ${d._channel || 'inconnu'} non supporté par le système`,
  _platform_post_id: null,
  _orphans: {}
} }];

// ============================================================
// CONVERGENCE — Normaliser résultat connecteur (Normalizer Pattern)
// ============================================================
const result   = $input.first().json;
const initData = $('Recevoir job_id').first().json;

if (result._success) {
  return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
    ...initData,
    _final_status:     'PUBLISHED',
    _platform_post_id: result._platform_post_id,
    _error_code:       null,
    _error_message:    null
  } }];
}

return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  ...initData,
  _final_status:     result._status || 'FAILED_PUBLICATION',
  _platform_post_id: null,
  _error_code:       result._error_code,
  _error_message:    result._error_message,
  _orphans:          result._orphans || {}
} }];

// UPDATE JOB avec le statut final + retry_count
const d = $input.first().json;
const job = $('Extraire + Valider Job').first().json.job || {};
const fields = {
  status:           d._final_status,
  platform_post_id: d._platform_post_id || '',
  retry_count:      (job.retry_count || 0) + (d._final_status !== 'PUBLISHED' ? 1 : 0)
};
if (d._error_code) {
  fields.last_error = JSON.stringify({
    error_code:    d._error_code,
    error_message: d._error_message,
    ...(d._orphans && Object.keys(d._orphans).length > 0 ? { orphan_objects: d._orphans } : {})
  });
}
return [{ json: { action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id, job_id: d.job_id, fields } }];

const d = $('Traiter résultat connecteur').first().json;
const isSuccess = d._final_status === 'PUBLISHED';
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  agent:          'PUBLICATION_AGENT',
  event_type:     isSuccess ? 'PUBLICATION_COMPLETED' : 'PUBLICATION_FAILURE',
  message:        isSuccess
    ? `Publication réussie, platform_post_id=${d._platform_post_id}`
    : `Échec: ${d._error_code} — ${d._error_message}`,
  job_id:         d.job_id,
  correlation_id: d.correlation_id
} }];

// Réponse V2 vers l'Orchestrateur — branche publication
const d = $('Traiter résultat connecteur').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  status:         'SUCCESS',
  source:         'PUBLICATION_AGENT',
  target:         'ORCHESTRATOR',
  correlation_id: d.correlation_id,
  in_reply_to:    d.incoming_message_id || null,
  payload: {
    job_id:         d.job_id,
    result_status:  d._final_status,
    platform_post_id: d._platform_post_id || null,
    error_code:     d._error_code || null,
    error_message:  d._error_message || null
  }
} }];

// ============================================================
// BRANCHE ÉCHEC — Update job avec statut d'erreur
// PUBLICATION_DEFERRED : le job RESTE en ADAPTED (spec UC-03 §7.4)
// ============================================================
const d = $input.first().json;

// Pour DEFERRED, le job reste en ADAPTED (reprise automatique possible)
const status = (d._result_status === 'PUBLICATION_DEFERRED') ? 'ADAPTED' : d._result_status;

const fields = {
  status,
  last_error: JSON.stringify({
    error_code:    d._error_code,
    error_message: d._error_message
  })
};

return [{ json: {
  action: 'UPDATE_JOB', tenant_id: $('Recevoir job_id').first().json.tenant_id,
  job_id: d.job_id,
  fields,
  // Transmettre les données nécessaires aux nodes suivants
  _result_status:     d._result_status,
  _error_code:        d._error_code,
  _error_message:     d._error_message,
  correlation_id:     d.correlation_id,
  incoming_message_id: d.incoming_message_id
} }];

const d = $('Prép UPDATE échec').first().json;
const eventType = (d._result_status === 'PUBLICATION_DEFERRED')
  ? 'PUBLICATION_DEFERRED'
  : (d._result_status === 'FAILED_CREDENTIALS')
    ? d._error_code   // ex: CREDENTIAL_NOT_FOUND, CREDENTIAL_PLATFORM_MISMATCH
    : 'FAILED_PRE_PUBLICATION';
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  agent:          'PUBLICATION_AGENT',
  event_type:     eventType,
  message:        `${d._result_status}: ${d._error_message} pour ${d.job_id}`,
  job_id:         d.job_id,
  correlation_id: d.correlation_id
} }];

// Réponse V2 vers l'Orchestrateur — branche échec
// CORRIGÉ : in_reply_to désormais inclus (cohérence V2)
const d = $('Prép UPDATE échec').first().json;
return [{ json: { tenant_id: $('Recevoir job_id').first().json.tenant_id, client_id: $('Recevoir job_id').first().json.client_id, 
  status:         'SUCCESS',
  source:         'PUBLICATION_AGENT',
  target:         'ORCHESTRATOR',
  correlation_id: d.correlation_id,
  in_reply_to:    d.incoming_message_id || null,
  payload: {
    job_id:        d.job_id,
    result_status: d._result_status,
    error_code:    d._error_code,
    error_message: d._error_message
  }
} }];
